import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";
import api from "../utils/api";

const STATUS_LABEL = { pending:"Хүлээгдэж буй", confirmed:"Баталгаажсан",
  cancelled:"Цуцлагдсан", completed:"Дууссан" };
const STATUS_CLASS = { pending:"badge-pending", confirmed:"badge-confirmed",
  cancelled:"badge-cancelled", completed:"badge-completed" };

export default function AdminPage() {
  const { user, isAdmin } = useAuth();
  const nav = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [stats, setStats]       = useState({});
  const [loading, setLoading]   = useState(true);
  const [tab, setTab]           = useState("today");
  const [statusF, setStatusF]   = useState("all");
  const [date, setDate]         = useState(new Date().toISOString().slice(0,10));

  useEffect(() => {
    if (!user || !isAdmin) { nav("/"); return; }
    loadStats();
    load();
  }, []); // eslint-disable-line

  useEffect(() => { load(); }, [tab, statusF, date]); // eslint-disable-line

  const loadStats = async () => {
    const { data } = await api.get("/admin/stats");
    setStats(data.data);
  };

  const load = async () => {
    setLoading(true);
    try {
      const q = new URLSearchParams();
      if (statusF !== "all") q.set("status", statusF);
      if (tab === "today") q.set("date", new Date().toISOString().slice(0,10));
      else if (tab === "date") q.set("date", date);
      const { data } = await api.get(`/bookings/admin?${q}`);
      setBookings(data.data);
    } catch { setBookings([]); }
    setLoading(false);
  };

  const confirm = async (id) => {
    await api.put(`/bookings/${id}/confirm`);
    load(); loadStats();
  };

  const cancel = async (id) => {
    if (!window.confirm("Захиалгыг цуцлах уу?")) return;
    await api.put(`/bookings/${id}/cancel`);
    load(); loadStats();
  };

  const fmt = dt => new Date(dt).toLocaleString("mn-MN", {
    month:"2-digit", day:"2-digit", hour:"2-digit", minute:"2-digit"
  });

  const STAT_CARDS = [
    { label:"НИЙТ ЗАХИАЛГА",   value: stats.total,     delta:"+12.5%", color:"#2563EB", icon:"📊" },
    { label:"ХҮЛЭЭГДЭЖ БУЙ",   value: stats.pending,   delta:"8.2%",   color:"#F59E0B", icon:"⏳" },
    { label:"БАТАЛГААЖСАН",     value: stats.confirmed, delta:"-2.1%",  color:"#22C55E", icon:"✅" },
  ];

  return (
    <div style={{ maxWidth:1100, margin:"0 auto", padding:"32px 20px" }}>
      {/* Header */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:28 }}>
        <div>
          <h1 style={{ fontSize:26, fontWeight:800, marginBottom:4 }}>Админ хянах самбар</h1>
          <p style={{ color:"var(--muted)", fontSize:13 }}>Системийн нийт захиалга болон төлөв байдлыг хянах</p>
        </div>
        <button className="btn btn-primary" style={{ display:"flex", alignItems:"center", gap:6 }}>
          + Шинэ захиалга
        </button>
      </div>

      {/* Stats */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:16, marginBottom:28 }}>
        {STAT_CARDS.map(s => (
          <div key={s.label} className="card" style={{ padding:20 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:12 }}>
              <span style={{ fontSize:22 }}>{s.icon}</span>
              <span style={{ fontSize:12, fontWeight:600, color: s.delta.startsWith("+") ? "var(--green)" : s.delta.startsWith("-") ? "var(--red)" : "var(--amber)" }}>
                {s.delta.startsWith("+") ? "↑" : s.delta.startsWith("-") ? "↓" : "↗"} {s.delta}
              </span>
            </div>
            <div style={{ fontSize:11, color:"var(--muted)", letterSpacing:"0.08em", marginBottom:4 }}>
              {s.label}
            </div>
            <div style={{ fontSize:36, fontWeight:800, color:"var(--text)" }}>
              {s.value ?? "—"}
            </div>
          </div>
        ))}
      </div>

      {/* Table card */}
      <div className="card" style={{ padding:0, overflow:"hidden" }}>
        {/* Table header */}
        <div style={{ padding:"16px 20px", borderBottom:"1px solid var(--border)",
          display:"flex", gap:4, alignItems:"center", flexWrap:"wrap" }}>
          {[["today","Өнөөдөр"],["week","Энэ долоо хоног"],["month","Энэ сар"],["all","Бүх цаг үе"]].map(([k,l])=>(
            <button key={k} onClick={()=>setTab(k)} style={{
              padding:"6px 14px", borderRadius:6, fontSize:13, fontWeight:500,
              cursor:"pointer", border:"none",
              background: tab===k ? "transparent" : "transparent",
              color: tab===k ? "var(--text)" : "var(--muted)",
              borderBottom: tab===k ? "2px solid var(--blue)" : "2px solid transparent",
            }}>{l}</button>
          ))}
          <div style={{ marginLeft:"auto", display:"flex", gap:8 }}>
            <select value={statusF} onChange={e=>setStatusF(e.target.value)}
              style={{ padding:"6px 12px", background:"var(--surface)", border:"1px solid var(--border)",
                borderRadius:6, color:"var(--text)", fontSize:13, cursor:"pointer" }}>
              <option value="all">Бүх төрөл</option>
              <option value="pending">Хүлээгдэж буй</option>
              <option value="confirmed">Баталгаажсан</option>
              <option value="cancelled">Цуцлагдсан</option>
              <option value="completed">Дууссан</option>
            </select>
            {tab === "date" && (
              <input type="date" value={date} onChange={e=>setDate(e.target.value)}
                className="input" style={{ width:160 }} />
            )}
          </div>
        </div>

        {/* Table */}
        <div style={{ overflowX:"auto" }}>
          <table style={{ width:"100%", borderCollapse:"collapse" }}>
            <thead>
              <tr style={{ borderBottom:"1px solid var(--border)" }}>
                {["ХЭРЭГЛЭГЧ","ҮЙЛЧИЛГЭЭ","ЦАГ","ТӨЛӨВ","ҮЙЛДЭЛ"].map(h => (
                  <th key={h} style={{ padding:"12px 16px", textAlign:"left",
                    fontSize:11, color:"var(--muted)", letterSpacing:"0.08em", fontWeight:600 }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={5} style={{ padding:32, textAlign:"center", color:"var(--muted)" }}>
                  Ачаалж байна...
                </td></tr>
              ) : bookings.length === 0 ? (
                <tr><td colSpan={5} style={{ padding:32, textAlign:"center", color:"var(--muted)" }}>
                  Захиалга байхгүй
                </td></tr>
              ) : bookings.map(b => (
                <tr key={b._id} style={{ borderBottom:"1px solid var(--border)" }}
                  onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.02)"}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <td style={{ padding:"12px 16px" }}>
                    <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                      <div style={{
                        width:34, height:34, borderRadius:"50%",
                        background:"var(--blue)", display:"flex",
                        alignItems:"center", justifyContent:"center",
                        fontSize:13, fontWeight:700, flexShrink:0,
                      }}>{b.userId?.name?.charAt(0)}</div>
                      <div>
                        <div style={{ fontWeight:500, fontSize:13 }}>{b.userId?.name}</div>
                        <div style={{ fontSize:11, color:"var(--muted)" }}>
                          {b.userId?.phone?.replace(/(\d{4})\d{4}/, "$1****")}
                        </div>
                      </div>
                    </div>
                  </td>
                  <td style={{ padding:"12px 16px" }}>
                    <div style={{ fontSize:13 }}>
                      <span style={{ marginRight:6 }}>✂</span>
                      {b.businessId?.name} — {b.serviceId?.name}
                    </div>
                  </td>
                  <td style={{ padding:"12px 16px", fontSize:13, color:"var(--muted)" }}>
                    {fmt(b.datetime)} — {
                      (() => {
                        const d = new Date(b.datetime);
                        d.setMinutes(d.getMinutes() + (b.serviceId?.duration||60));
                        return d.toLocaleTimeString("mn-MN",{hour:"2-digit",minute:"2-digit"});
                      })()
                    }
                  </td>
                  <td style={{ padding:"12px 16px" }}>
                    <span className={`badge ${STATUS_CLASS[b.status]}`}>
                      {STATUS_LABEL[b.status]}
                    </span>
                  </td>
                  <td style={{ padding:"12px 16px" }}>
                    <div style={{ display:"flex", gap:6 }}>
                      {b.status === "pending" && (
                        <button onClick={()=>confirm(b._id)} className="btn btn-primary btn-sm">
                          Баталгаажуулах
                        </button>
                      )}
                      {["pending","confirmed"].includes(b.status) && (
                        <button onClick={()=>cancel(b._id)} className="btn btn-danger btn-sm">
                          Цуцлах
                        </button>
                      )}
                      {b.status === "cancelled" && (
                        <button className="btn btn-outline btn-sm">Дэлгэрэнгүй</button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Footer */}
        {bookings.length > 0 && (
          <div style={{ padding:"12px 20px", borderTop:"1px solid var(--border)",
            display:"flex", justifyContent:"space-between", alignItems:"center",
            color:"var(--muted)", fontSize:12 }}>
            <span>Нийт {bookings.length} бичлэгээс 1–{bookings.length} харуулж байна</span>
            <div style={{ display:"flex", gap:4 }}>
              {["‹","1","2","3","›"].map(p => (
                <button key={p} style={{
                  width:28, height:28, borderRadius:4,
                  background: p==="1" ? "var(--blue)" : "var(--card)",
                  border:"1px solid", borderColor: p==="1" ? "var(--blue)" : "var(--border)",
                  color: p==="1" ? "#fff" : "var(--muted)",
                  cursor:"pointer", fontSize:12,
                }}>{p}</button>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
